const unsigned char *getPathData(Icon icon)
{
    switch (icon)
    {
    case Icon::Play:
        return playPathData;
    case Icon::Pause:
        return pausePathData;
    case Icon::Stop:
        return stopPathData;
    case Icon::Open:
        return openPathData;
    case Icon::Folder:
        return folderPathData;
    case Icon::Settings:
        return settingsPathData;
    };

    throw std::runtime_error("Icon data not found");
}

const size_t getPathDataSize(Icon icon)
{
    switch (icon)
    {
    case Icon::Play:
        return sizeof(playPathData);
    case Icon::Pause:
        return sizeof(pausePathData);
    case Icon::Stop:
        return sizeof(stopPathData);
    case Icon::Open:
        return sizeof(openPathData);
    case Icon::Folder:
        return sizeof(folderPathData);
    case Icon::Settings:
        return sizeof(settingsPathData);
    };

    throw std::runtime_error("Icon data not found");
}

juce::Path Resources::getIconPath(Icon icon)
{
    auto pathData = getPathData(icon);
    auto numberOfBytes = getPathDataSize(icon);

    juce::Path path;
    path.loadPathFromData(pathData, numberOfBytes);

    // Normalise it to 0.0 - 1.0 range
    auto bounds = path.getBounds();

    juce::Path normalisedPath;
    normalisedPath.addPath(path, juce::AffineTransform::translation(-bounds.getX(), -bounds.getY())
                                     .scaled(1.0f / bounds.getWidth(),
                                             1.0f / bounds.getHeight()));
    return normalisedPath;
}

std::shared_ptr<juce::DrawablePath> Resources::getIconDrawable(Icon icon, juce::Colour strokeFill, float strokeThickness)
{
    juce::Path normalisedPath = Resources::getIconPath(icon);

    auto drawable = std::make_shared<juce::DrawablePath>();
    drawable->setPath(normalisedPath);
    drawable->setFill(juce::Colours::transparentWhite);
    drawable->setStrokeFill(strokeFill);
    drawable->setStrokeThickness(strokeThickness);

    return drawable;
}